// 本地存储管理模块 - 使用 chrome.storage

const Storage = {
  // 存储键名
  KEYS: {
    CUSTOM_MODELS: 'chatbot_custom_models',  // 自定义模型列表
    GROUPS: 'chatbot_groups',                // 分组信息
    PREFERENCES: 'chatbot_preferences',      // 用户偏好
    HIDDEN_MODELS: 'chatbot_hidden_models'   // 隐藏的内置模型
  },

  /**
   * 获取所有自定义模型
   * @returns {Promise<Array>} 自定义模型列表
   */
  async getCustomModels() {
    return new Promise((resolve) => {
      chrome.storage.local.get([this.KEYS.CUSTOM_MODELS], (result) => {
        resolve(result[this.KEYS.CUSTOM_MODELS] || []);
      });
    });
  },

  /**
   * 保存自定义模型
   * @param {Object} model - 模型信息
   * @returns {Promise<Array>} 更新后的模型列表
   */
  async saveCustomModel(model) {
    const models = await this.getCustomModels();
    const existingIndex = models.findIndex(m => m.id === model.id);

    const modelData = {
      id: model.id || `custom_${Date.now()}`,
      name: model.name,
      url: model.url,
      description: model.description || '',
      icon: model.icon || null,  // base64 图标
      groupId: model.groupId || 'default',
      color: model.color || this.generateRandomColor(),
      isCustom: true,
      createdAt: model.createdAt || Date.now(),
      updatedAt: Date.now()
    };

    if (existingIndex >= 0) {
      models[existingIndex] = modelData;
    } else {
      models.push(modelData);
    }

    return new Promise((resolve) => {
      chrome.storage.local.set({ [this.KEYS.CUSTOM_MODELS]: models }, () => {
        resolve(models);
      });
    });
  },

  /**
   * 删除自定义模型
   * @param {string} modelId - 模型 ID
   */
  async deleteCustomModel(modelId) {
    const models = await this.getCustomModels();
    const filteredModels = models.filter(m => m.id !== modelId);
    return new Promise((resolve) => {
      chrome.storage.local.set({ [this.KEYS.CUSTOM_MODELS]: filteredModels }, resolve);
    });
  },

  /**
   * 获取隐藏的内置模型 ID 列表
   */
  async getHiddenModels() {
    return new Promise((resolve) => {
      chrome.storage.local.get([this.KEYS.HIDDEN_MODELS], (result) => {
        resolve(result[this.KEYS.HIDDEN_MODELS] || []);
      });
    });
  },

  /**
   * 隐藏（删除）内置模型
   */
  async hideBuiltInModel(modelId) {
    const hidden = await this.getHiddenModels();
    if (!hidden.includes(modelId)) {
      hidden.push(modelId);
    }
    // 同时清除可能存在的自定义覆盖
    await this.deleteCustomModel(modelId);
    return new Promise((resolve) => {
      chrome.storage.local.set({ [this.KEYS.HIDDEN_MODELS]: hidden }, resolve);
    });
  },

  /**
   * 获取所有分组
   * @returns {Promise<Array>} 分组列表
   */
  async getGroups() {
    return new Promise((resolve) => {
      chrome.storage.local.get([this.KEYS.GROUPS], (result) => {
        const groups = result[this.KEYS.GROUPS] || [
          { id: 'default', name: '默认分组', icon: '🤖', order: 0, expanded: true },
          { id: 'chinese', name: '国内模型', icon: '🇨🇳', order: 1, expanded: true },
          { id: 'international', name: '国际模型', icon: '🌍', order: 2, expanded: true }
        ];
        resolve(groups.sort((a, b) => a.order - b.order));
      });
    });
  },

  /**
   * 保存分组
   * @param {Object} group - 分组信息
   * @returns {Promise<Array>} 更新后的分组列表
   */
  async saveGroup(group) {
    const groups = await this.getGroups();
    const existingIndex = groups.findIndex(g => g.id === group.id);

    const groupData = {
      id: group.id || `group_${Date.now()}`,
      name: group.name,
      icon: group.icon || '📁',
      order: group.order !== undefined ? group.order : groups.length,
      expanded: group.expanded !== false
    };

    if (existingIndex >= 0) {
      groups[existingIndex] = groupData;
    } else {
      groups.push(groupData);
    }

    return new Promise((resolve) => {
      chrome.storage.local.set({ [this.KEYS.GROUPS]: groups }, () => {
        resolve(groups);
      });
    });
  },

  /**
   * 删除分组
   * @param {string} groupId - 分组 ID
   */
  async deleteGroup(groupId) {
    if (groupId === 'default') return; // 不允许删除默认分组

    const groups = await this.getGroups();
    const filteredGroups = groups.filter(g => g.id !== groupId);

    // 将该分组下的模型移到默认分组
    const models = await this.getCustomModels();
    models.forEach(m => {
      if (m.groupId === groupId) {
        m.groupId = 'default';
      }
    });

    return new Promise((resolve) => {
      chrome.storage.local.set({
        [this.KEYS.GROUPS]: filteredGroups,
        [this.KEYS.CUSTOM_MODELS]: models
      }, resolve);
    });
  },

  /**
   * 切换分组展开/折叠状态
   * @param {string} groupId - 分组 ID
   */
  async toggleGroupExpanded(groupId) {
    const groups = await this.getGroups();
    const group = groups.find(g => g.id === groupId);
    if (group) {
      group.expanded = !group.expanded;
      return new Promise((resolve) => {
        chrome.storage.local.set({ [this.KEYS.GROUPS]: groups }, () => {
          resolve(group);
        });
      });
    }
  },

  /**
   * 获取按分组组织的模型列表
   * @returns {Promise<Object>} 按分组组织的模型
   */
  async getModelsByGroup() {
    const builtInModels = this.getBuiltInModels();
    const customModels = await this.getCustomModels();
    const groups = await this.getGroups();
    const hiddenModels = await this.getHiddenModels();

    // 读取侧边栏排序状态
    const orderState = await new Promise(resolve => {
      chrome.storage.local.get(['chatbot_model_order_state'], result => {
        resolve(result.chatbot_model_order_state || []);
      });
    });

    // 过滤隐藏的内置模型，自定义模型覆盖同 ID 的内置模型
    const customIds = new Set(customModels.map(m => m.id));
    const filteredBuiltIn = builtInModels.filter(m => !hiddenModels.includes(m.id) && !customIds.has(m.id));
    const allModels = [...filteredBuiltIn, ...customModels];

    if (orderState.length > 0) {
      const orderMap = new Map(orderState.map(item => [item.id, item.order]));
      allModels.forEach(model => {
        if (orderMap.has(model.id)) {
          model.order = orderMap.get(model.id);
        }
      });
    }

    // 按分组组织
    const result = {};
    groups.forEach(group => {
      result[group.id] = {
        group,
        models: allModels
          .filter(m => m.groupId === group.id || (!m.groupId && group.id === 'default'))
          .sort((a, b) => (a.order ?? 0) - (b.order ?? 0))
      };
    });

    // 处理未分组的模型
    const ungroupedModels = allModels.filter(m => {
      return !groups.find(g => g.id === m.groupId);
    });

    if (ungroupedModels.length > 0) {
      result['ungrouped'] = {
        group: { id: 'ungrouped', name: '其他', icon: '📦', order: 999, expanded: true },
        models: ungroupedModels
      };
    }

    return result;
  },

  /**
   * 生成随机颜色
   * @returns {string} 十六进制颜色
   */
  generateRandomColor() {
    const colors = ['#3b82f6', '#8b5cf6', '#ec4899', '#f59e0b', '#10b981', '#06b6d4', '#ef4444', '#6366f1'];
    return colors[Math.floor(Math.random() * colors.length)];
  },

  /**
   * 获取内置模型列表
   * @returns {Array} 内置模型
   */
  getBuiltInModels() {
    // 模型图标 (SVG base64) - 使用用户提供的 logo 文件
    const icons = {
      chatgpt: 'data:image/svg+xml;base64,',
      gemini: 'data:image/svg+xml;base64,',
      claude: 'data:image/svg+xml;base64,',
      grok: 'data:image/svg+xml;base64,',
      kimi: 'data:image/svg+xml;base64,',
      zhipu: 'data:image/svg+xml;base64,',
      ernie: 'data:image/svg+xml;base64,',
      qwen: 'data:image/svg+xml;base64,',
      deepseek: 'data:image/svg+xml;base64,',
      doubao: 'data:image/svg+xml;base64,'
    };

    return [
      { id: 'chatgpt', name: 'ChatGPT', url: 'https://chat.openai.com', icon: icons.chatgpt, color: '#000000', description: 'OpenAI 的旗舰大模型', groupId: 'international' },
      { id: 'gemini', name: 'Gemini', url: 'https://gemini.google.com', icon: icons.gemini, color: '#4285f4', description: 'Google 的多模态大模型', groupId: 'international' },
      { id: 'claude', name: 'Claude', url: 'https://claude.ai', icon: icons.claude, color: '#d97757', description: 'Anthropic 的 AI 助手', groupId: 'international' },
      { id: 'grok', name: 'Grok', url: 'https://grok.com', icon: icons.grok, color: '#000000', description: 'xAI 的 AI 助手', groupId: 'international' },
      { id: 'kimi', name: 'Kimi', url: 'https://kimi.moonshot.cn', icon: icons.kimi, color: '#ffffff', description: '月之暗面的长文本模型', groupId: 'chinese' },
      { id: 'zhipu', name: '智谱清言', url: 'https://chatglm.cn', icon: icons.zhipu, color: '#4c9aff', description: '清华智谱的 AI 助手', groupId: 'chinese' },
      { id: 'ernie', name: '文心一言', url: 'https://yiyan.baidu.com', icon: icons.ernie, color: '#2932e1', description: '百度的大语言模型', groupId: 'chinese' },
      { id: 'qwen', name: '通义千问', url: 'https://tongyi.aliyun.com', icon: icons.qwen, color: '#615ced', description: '阿里巴巴的通义大模型', groupId: 'chinese' },
      { id: 'deepseek', name: 'DeepSeek', url: 'https://chat.deepseek.com', icon: icons.deepseek, color: '#3b82f6', description: '深度求索的编程大模型', groupId: 'chinese' },
      { id: 'doubao', name: '豆包', url: 'https://doubao.com', icon: icons.doubao, color: '#22d3ee', description: '字节的 AI 助手', groupId: 'chinese' }
    ];
  },

  /**
   * 获取用户偏好设置
   * @returns {Promise<Object>} 偏好设置
   */
  async getPreferences() {
    return new Promise((resolve) => {
      chrome.storage.local.get([this.KEYS.PREFERENCES], (result) => {
        resolve(result[this.KEYS.PREFERENCES] || {
          theme: 'light',
          showDescription: true,
          layout: 'grid',
          sidebarEnabled: true
        });
      });
    });
  },

  /**
   * 保存用户偏好设置
   * @param {Object} preferences - 偏好设置
   */
  async savePreferences(preferences) {
    const currentPrefs = await this.getPreferences();
    const updatedPrefs = { ...currentPrefs, ...preferences };
    return new Promise((resolve) => {
      chrome.storage.local.set({ [this.KEYS.PREFERENCES]: updatedPrefs }, resolve);
    });
  },

  /**
   * 清除所有存储数据
   */
  async clearAll() {
    return new Promise((resolve) => {
      chrome.storage.local.clear(resolve);
    });
  },

  /**
   * 导出配置
   */
  async exportConfig() {
    const [customModels, groups, preferences] = await Promise.all([
      this.getCustomModels(),
      this.getGroups(),
      this.getPreferences()
    ]);
    return { customModels, groups, preferences, exportedAt: new Date().toISOString() };
  },

  /**
   * 导入配置
   * @param {Object} config - 配置数据
   */
  async importConfig(config) {
    if (config.customModels) {
      await new Promise(resolve => {
        chrome.storage.local.set({ [this.KEYS.CUSTOM_MODELS]: config.customModels }, resolve);
      });
    }
    if (config.groups) {
      await new Promise(resolve => {
        chrome.storage.local.set({ [this.KEYS.GROUPS]: config.groups }, resolve);
      });
    }
    if (config.preferences) {
      await this.savePreferences(config.preferences);
    }
  },

  /**
   * 保存模型使用状态
   * @param {string} modelId - 模型 ID
   * @param {Object} state - 状态数据
   */
  async saveModelState(modelId, state) {
    return new Promise((resolve) => {
      chrome.storage.local.get(['model_states'], (result) => {
        const states = result.model_states || {};
        states[modelId] = { ...state, lastUsed: Date.now() };
        chrome.storage.local.set({ model_states: states }, resolve);
      });
    });
  }
};
